osal_thread_t snmptrap_thread_create(char *pName, int stack_size, int thread_pri, void (f)(void *), void *pArg)
{
    pthread_attr_t  attr;
    pthread_t       id;

    if (0 != pthread_attr_init(&attr))
    {
        /* thread property configuration error */
        return (osal_thread_t)NULL;
    }

    pthread_attr_setstacksize(&attr, stack_size);

    if (pthread_create(&id, NULL, (void *)f, (void *)pArg))
    {
        return (osal_thread_t)NULL;
    }

    return ((osal_thread_t)id);
} /* end of osal_thread_create */
