int32 netsnmp_trap_send_mux(char *buf)
{
    int32 trapCode;

    if (NULL == buf)
        return SYS_ERR_FAILED;

    trapCode = atoi(buf);
    //snmp_log(LOG_DEBUG, "Snmp trap code:%d \n", trapCode);

    switch(trapCode)
    {
        case SNMP_TRAP_CODE_COLD_START:
            send_coldStart_trap();
            break;

        case SNMP_TRAP_CODE_WARM_START:
            send_warmStart_trap();
            break;

        case SNMP_TRAP_CODE_LINKDOWN:
            send_linkDown_trap(buf);
            break;

        case SNMP_TRAP_CODE_LINKUP:
            send_linkUp_trap(buf);
            break;

/*
        case SNMP_TRAP_CODE_AUTH_FAILD:
            send_authenticationFailure_trap();
            break;
*/
        case SNMP_TRAP_CODE_PORT_SECURITY:
            send_portSecurity_trap(buf);
            break;

         default:
            break;
    }

    //10ms
    usleep(10*1000);
    return SYS_ERR_OK;
}



int netsnmp_trap_send(void)
{
    uint64 sysUptime = 0;
    int i;
    sys_snmp_notifyMsg_t notifyMsg;
    uint32 trapCode = 0;

    if (_isSysStartTime)
    {
        sal_snmp_sysUpTimeGep_get(&sysUptime);
        if (sysUptime/100 > SNMP_SYS_STARTTIME_KEEP)
        {
            _isSysStartTime = FALSE;
        }
    }
    //start time, not process
    if (_isSysStartTime)
        return SYS_ERR_FAILED;

    for (i = 0; i < SNMP_NOTIFY_MAX_BUF; i++)
    {
        SYS_MEM_CLEAR(notifyMsg);
        SYS_ERR_CONTINUE(_sal_snmp_notifyMsg_get(i, &notifyMsg));
        if (notifyMsg.valid)
        {
        	trapCode = atoi(notifyMsg.trapMsg);
        	if(trapCode > SNMP_CMTRAP_CODE_START)
        	{
				netsnmp_cmTrap_send_mux(trapCode, notifyMsg.trapMsg);
        	}
        	else 
        	{
            	netsnmp_trap_send_mux(notifyMsg.trapMsg);
            }
            
            notifyMsg.valid = FALSE;
            _sal_snmp_notifyMsg_set(i, &notifyMsg);
        }
    }
	return SYS_ERR_OK;
}

int monitorSysReadySnmpTrapTimerProcess(struct thread *t)
{
	int ret = 0;
	ret = netsnmp_trap_send();
	if(ret != SYS_ERR_OK)
		thread_add_timer(master, monitorSysReadySnmpTrapTimerProcess, NULL, 4);
		
    return 0;
}

