/*꾸鱗휑羚돨句口룐陋 뒤寧몸꽝鑒槨狼룐陋돨句口 뒤랗몸꽝鑒珂쇌，뒤힛몸槨잚謹， 뒤愷몸槨쏵넋ID 뒤巧몸槨코휭*/
int32 snmpTrapOperatingMessageEncapsulation(snmp_trapFormat_t *pMsg, char* timestr, char* type, uint32 pid, char* detail)
{
	//snmp_trapFormat_t info;
	sys_line_session_t session;
	char typestr[50] ={0};
	va_list args;
	int i = 0;

	if(pMsg == NULL && timestr == NULL)
		return -1;
			
	osal_memset(pMsg, 0, sizeof(snmp_trapFormat_t));
	osal_memset(&session, 0, sizeof(sys_line_session_t));

	/*輕념珂쇌*/
	osal_sprintf(pMsg->trapTime, "%s", timestr);
	
	/*輕념꾸鱗잚謹*/
	osal_sprintf(pMsg->trapType, "%s", type);

	/*朞輕痰빵꾸鱗斤口*/
	sal_sys_lineSession_by_pid_get(pid, &session, typestr);
    if(osal_strcmp(typestr, "snmp") != 0)
    {	
		osal_sprintf(pMsg->trapUser,"%s user:%s %s", typestr, session.user, session.host);
    }
    else
    {
		osal_sprintf(pMsg->trapUser,"snmp");
    }
	/*圈玖코휭輕념*/
    osal_sprintf(pMsg->trapDetail, "%s", detail);

	//snmp_log(LOG_DEBUG, "%s %d type=%s user=%s detail=%s\n", __func__, __LINE__, pMsg->trapType ,pMsg->trapUser, pMsg->trapDetail);

    return  0;
}

