/******************************************************************************
변鑒츰냔：snmpTrapAppWrapFunction
묘콘췄甘：鬧꿍욋변鑒句口직썩驕변鑒
渴흙꽝鑒：轟
渴놔꽝鑒：轟
변鑒럿쀼：VD_E_NONE, 냥묘
          SYS_ERR_FAILED，獵契呵겨
          VD_E_PARAM，꽝鑒댄轎
페劍綱츠：瞳쏵넋쌈澗句口裂품딧痰
******************************************************************************/
int snmpTrapAppWrapFunction(void)
{
    int iRet = SYS_ERR_OK;

    memset(snmpTrapServerWrap, 0, (TRAP_FUNC_MAX * sizeof(SMD_WRAP_CMD)));
	if(snmpTrapServerWrap == NULL)
	{
		snmp_log(LOG_DEBUG, "\r %s %d pSmdWrap == NULL\n", __func__, __LINE__);
	}

	iRet += smdAppWrapRegister(TRAP_FUNC_START, 0, snmpTrapWrapSystemStart, snmpTrapServerWrap, TRAP_FUNC_MAX);
	iRet += smdAppWrapRegister(TRAP_FUNC_REBOOT, 0, snmpTrapWrapSystemReboot, snmpTrapServerWrap, TRAP_FUNC_MAX);
	iRet += smdAppWrapRegister(TRAP_FUNC_OPERATE, 0, snmpTrapWrapOperateMessage, snmpTrapServerWrap, TRAP_FUNC_MAX);
	iRet += smdAppWrapRegister(TRAP_FUNC_PORT_LINK, 0, snmpTrapWrapPortLinkStatus, snmpTrapServerWrap, TRAP_FUNC_MAX);
	iRet += smdAppWrapRegister(TRAP_FUNC_LOGIN_MESSAGES, 0, snmpTrapWrapLoginAAAStatus, snmpTrapServerWrap, TRAP_FUNC_MAX);
	iRet += smdAppWrapRegister(TRAP_FUNC_LOGIN_PASSWORD_CHANGE, 0, snmpTrapWrapLoginPasswordChStatus, snmpTrapServerWrap, TRAP_FUNC_MAX);
	iRet += smdAppWrapRegister(TRAP_FUNC_USER_OPERATION, 0, snmpTrapWrapUserOperationStatus, snmpTrapServerWrap, TRAP_FUNC_MAX);
    iRet += smdAppWrapRegister(TRAP_FUNC_USER_OPERATION_INFO, 0, snmpTrapWrapUserOperationInfo, snmpTrapServerWrap, TRAP_FUNC_MAX);


    if ( SYS_ERR_OK != iRet )
    {
        //smdDebugPrintf(SMD_DEBUG_WRAP_ERR, "%s:register failed", __func__);
    }

    return iRet;
}

int snmpTrapAppWrapProcess(SMD_MSG *pMsg)
{
	int iRet = SYS_ERR_OK;
	iRet = smdCfgAppWrapProcess(pMsg, snmpTrapServerWrap, TRAP_FUNC_MAX);
	if ( SYS_ERR_OK != iRet )
    {
        snmp_log( LOG_DEBUG, "%s:register failed", __func__);
    }
    return iRet;
}

/* Read data via smd socket. */
static int
trap_thread_read (struct thread *thread)
{
  int iRet = 0;
  int i;
  int nbytes;
  unsigned char buf[1024];
  SMD_MSG            *pSmdMsg;
  VOS_MSG_ADDR        clientAddr;

  int sock = THREAD_FD (thread);
  //snmp_log(LOG_DEBUG, "%s %d\n", __func__, __LINE__);

  //while(1)
  {
	  /* Read raw data from socket */
	  iRet = vosMsgRecv(sock, buf, 1024, VOS_TIMEOUT_NOWAIT, &clientAddr);
	  if (iRet < 0)
	  {
	  	  goto end;
	  }
	  else
	  {
		/*늪뇹狼隣捲壇뇹잿*/
		pSmdMsg = (SMD_MSG *)buf;
		switch ( pSmdMsg->usType )
	    {

	        case SMD_MSG_TYPE_TRAP:
	        	//snmp_log(LOG_DEBUG, "%s %d\n", __func__, __LINE__);
	            iRet = snmpTrapAppWrapProcess(pSmdMsg);
	            break;
	        
	        default:
	            snmp_log(LOG_DEBUG, "\r\n%s:vosMsgRecv receive unkown msg %d", __func__, pSmdMsg->usType);
	            goto end;
	    }

		iRet = vosMsgResp(sock, iRet, pSmdMsg, pSmdMsg->usArgsBufLen + sizeof(SMD_MSG), &clientAddr);
	  }
	}
end:
  thread_add_read (master, trap_thread_read, (void *)sock, sock);
  return 0;
}


